function cua_handle_registration() {
    global $wpdb;
    $table_name = $wpdb->prefix . 'cua_users';

    $username = sanitize_user($_POST['cua_username']);
    $email = sanitize_email($_POST['cua_email']);
    $password = $_POST['cua_password'];
    $confirm = $_POST['cua_confirm_password'];

    if ($password !== $confirm) {
        $_SESSION['cua_reg_msg'] = "Passwords do not match.";
        return;
    }

    // Check if username already exists
    $existing = $wpdb->get_var($wpdb->prepare("SELECT COUNT(*) FROM $table_name WHERE username = %s", $username));
    if ($existing > 0) {
        $_SESSION['cua_reg_msg'] = "Username already exists.";
        return;
    }

    // Hash password
    $hashed_password = password_hash($password, PASSWORD_DEFAULT);

    $result = $wpdb->insert($table_name, array(
        'username' => $username,
        'email'    => $email,
        'password' => $hashed_password
    ), array('%s', '%s', '%s'));

    if ($result !== false) {
        $_SESSION['cua_reg_msg'] = "Registration successful.";
    } else {
        $_SESSION['cua_reg_msg'] = "Registration failed.";
    }
}

