function cua_handle_login() {
    global $wpdb;
    $table_name = $wpdb->prefix . 'cua_users';

    $username = sanitize_user($_POST['cua_login_username']);
    $password = $_POST['cua_login_password'];

    $user = $wpdb->get_row($wpdb->prepare("SELECT * FROM $table_name WHERE username = %s", $username));

    if (!$user) {
        $_SESSION['cua_login_msg'] = "Invalid username or password.";
        return;
    }

    if (password_verify($password, $user->password)) {
        $_SESSION['cua_authenticated'] = true;
        $_SESSION['cua_username'] = $username;
        $_SESSION['cua_login_msg'] = "Login successful. Welcome, " . esc_html($username) . "!";
    } else {
        $_SESSION['cua_login_msg'] = "Invalid username or password.";
    }
}

